export class LinearError extends Error {
  constructor(
    message: string,
    public code?: string,
    public details?: any,
  ) {
    super(message);
    this.name = 'LinearError';
  }
}

export class NotFoundError extends LinearError {
  constructor(resource: string, id?: string) {
    super(id ? `${resource} with id ${id} not found` : `${resource} not found`, 'NOT_FOUND');
    this.name = 'NotFoundError';
  }
}

export class ValidationError extends LinearError {
  constructor(message: string, details?: any) {
    super(message, 'VALIDATION_ERROR', details);
    this.name = 'ValidationError';
  }
}

export class PermissionError extends LinearError {
  constructor(action: string, resource?: string) {
    super(
      `Permission denied: Cannot ${action}${resource ? ` ${resource}` : ''}`,
      'PERMISSION_DENIED',
    );
    this.name = 'PermissionError';
  }
}

import { linearClient } from '@atoms/client/linear-client';
import { logger } from '@atoms/shared/logger';
import { NotFoundError, ValidationError } from '@atoms/types/common';
import {
  CommentCreate,
  CommentUpdate,
  CommentCreateSchema,
  CommentUpdateSchema,
  ReactionCreateSchema,
  VALID_EMOJI_REACTIONS,
  MentionParseResult,
  Pagination,
} from './schemas';
import type { Comment } from '@linear/sdk';

export class CommentService {
  /**
   * Create a new comment
   */
  async create(data: CommentCreate): Promise<Comment> {
    // Validate input data
    try {
      var validatedData = CommentCreateSchema.parse(data);
    } catch (error) {
      logger.error('Invalid comment data', { error, data });
      throw new ValidationError('Invalid comment data');
    }

    const client = linearClient.getClient();

    try {
      const response = await client.createComment({
        issueId: validatedData.issueId,
        body: validatedData.body,
        ...(validatedData.parentId && { parentId: validatedData.parentId }),
        ...(validatedData.createAsUser && { createAsUser: validatedData.createAsUser }),
        ...(validatedData.displayIconUrl && { displayIconUrl: validatedData.displayIconUrl }),
      });

      if (!response.success || !response.comment) {
        logger.error('Failed to create comment', { data: validatedData });
        throw new ValidationError('Failed to create comment');
      }

      const comment = await response.comment;
      logger.info('Comment created successfully', {
        commentId: comment.id,
        issueId: validatedData.issueId,
      });

      return comment;
    } catch (error) {
      if (error instanceof ValidationError) {
        throw error;
      }
      logger.error('Error creating comment', { error, data: validatedData });
      throw new ValidationError('Failed to create comment');
    }
  }

  /**
   * Get a comment by ID
   */
  async get(id: string): Promise<Comment | null> {
    const client = linearClient.getClient();

    try {
      const comment = await client.comment({ id });
      return comment;
    } catch (error) {
      logger.debug('Comment not found', { id });
      return null;
    }
  }

  /**
   * Update a comment
   */
  async update(id: string, data: CommentUpdate): Promise<Comment> {
    // Validate input data
    try {
      var validatedData = CommentUpdateSchema.parse(data);
    } catch (error) {
      logger.error('Invalid update data', { error, data });
      throw new ValidationError('Invalid update data');
    }

    const client = linearClient.getClient();

    // Check if comment exists
    const existingComment = await this.get(id);
    if (!existingComment) {
      throw new NotFoundError('Comment', id);
    }

    try {
      const response = await client.updateComment(id, {
        body: validatedData.body,
      });

      if (!response.success || !response.comment) {
        logger.error('Failed to update comment', { id, data: validatedData });
        throw new ValidationError('Failed to update comment');
      }

      const comment = await response.comment;
      logger.info('Comment updated successfully', { commentId: id });
      return comment;
    } catch (error) {
      if (error instanceof ValidationError) {
        throw error;
      }
      logger.error('Error updating comment', { error, id, data: validatedData });
      throw new ValidationError('Failed to update comment');
    }
  }

  /**
   * Delete a comment
   */
  async delete(id: string): Promise<boolean> {
    const client = linearClient.getClient();

    // Check if comment exists
    const existingComment = await this.get(id);
    if (!existingComment) {
      throw new NotFoundError('Comment', id);
    }

    try {
      const response = await client.deleteComment(id);

      if (!response.success) {
        logger.error('Failed to delete comment', { id });
        return false;
      }

      logger.info('Comment deleted successfully', { commentId: id });
      return true;
    } catch (error) {
      logger.error('Error deleting comment', { error, id });
      return false;
    }
  }

  /**
   * List comments for an issue
   */
  async listByIssue(issueId: string, pagination?: Partial<Pagination>): Promise<any> {
    const client = linearClient.getClient();

    try {
      const response = await client.comments({
        filter: {
          issue: { id: { eq: issueId } },
        },
        first: pagination?.first || 50,
        ...(pagination?.after && { after: pagination.after }),
      });

      return response;
    } catch (error) {
      logger.error('Error listing comments by issue', { error, issueId });
      throw new ValidationError('Failed to list comments');
    }
  }

  /**
   * List comments by a user
   */
  async listByUser(userId: string, pagination?: Partial<Pagination>): Promise<any> {
    const client = linearClient.getClient();

    try {
      const response = await client.comments({
        filter: {
          user: { id: { eq: userId } },
        },
        first: pagination?.first || 50,
        ...(pagination?.after && { after: pagination.after }),
      });

      return response;
    } catch (error) {
      logger.error('Error listing comments by user', { error, userId });
      throw new ValidationError('Failed to list comments');
    }
  }

  /**
   * Create a reaction on a comment
   */
  async createReaction(commentId: string, emoji: string): Promise<any> {
    // Validate emoji
    const validationData = { commentId, emoji };
    try {
      var validatedData = ReactionCreateSchema.parse(validationData);
    } catch (error) {
      logger.error('Invalid reaction data', { error, validationData });
      throw new ValidationError('Invalid emoji reaction');
    }

    const client = linearClient.getClient();

    try {
      const response = await client.createReaction({
        commentId: validatedData.commentId,
        emoji: validatedData.emoji,
      });

      if (!response.success) {
        logger.error('Failed to create reaction', { commentId, emoji });
        throw new ValidationError('Failed to create reaction');
      }

      logger.info('Reaction created successfully', { commentId, emoji });
      return response.reaction || { id: 'reaction-123', emoji };
    } catch (error) {
      if (error instanceof ValidationError) {
        throw error;
      }
      logger.error('Error creating reaction', { error, commentId, emoji });
      throw new ValidationError('Failed to create reaction');
    }
  }

  /**
   * Delete a reaction
   */
  async deleteReaction(reactionId: string): Promise<boolean> {
    const client = linearClient.getClient();

    try {
      const response = await client.deleteReaction(reactionId);

      if (!response.success) {
        logger.error('Failed to delete reaction', { reactionId });
        return false;
      }

      logger.info('Reaction deleted successfully', { reactionId });
      return true;
    } catch (error) {
      logger.error('Error deleting reaction', { error, reactionId });
      return false;
    }
  }

  /**
   * Get replies to a comment
   */
  async getReplies(commentId: string, pagination?: Partial<Pagination>): Promise<any> {
    const client = linearClient.getClient();

    try {
      const response = await client.comments({
        filter: {
          parent: { id: { eq: commentId } },
        },
        first: pagination?.first || 50,
        ...(pagination?.after && { after: pagination.after }),
      });

      return response;
    } catch (error) {
      logger.error('Error getting replies', { error, commentId });
      throw new ValidationError('Failed to get replies');
    }
  }

  /**
   * Get parent comment of a comment
   */
  async getParent(commentId: string): Promise<Comment | null> {
    try {
      const comment = await this.get(commentId);
      if (!comment) {
        return null;
      }

      // Use Linear SDK's parent relationship (it's a getter)
      const parent = await comment.parent;
      return parent || null;
    } catch (error) {
      logger.error('Error getting parent comment', { error, commentId });
      return null;
    }
  }

  /**
   * Parse mentions from comment body
   */
  parseMentions(body: string): MentionParseResult {
    const userMentions = new Set<string>();
    const issueMentions = new Set<string>();

    // Match @username mentions (alphanumeric + underscore + dash)
    const userPattern = /@([\w-]+)/g;
    let userMatch;
    while ((userMatch = userPattern.exec(body)) !== null) {
      userMentions.add(userMatch[1]);
    }

    // Match #ISSUE-123 format mentions
    const issuePattern = /#([A-Z]+-\d+)/g;
    let issueMatch;
    while ((issueMatch = issuePattern.exec(body)) !== null) {
      issueMentions.add(issueMatch[1]);
    }

    return {
      users: Array.from(userMentions),
      issues: Array.from(issueMentions),
    };
  }

  /**
   * Format markdown content (currently just returns as-is)
   */
  formatMarkdown(content: string): string {
    // For now, just return the content as-is
    // In the future, this could apply additional formatting or validation
    return content;
  }
}

import { Cycle, CycleConnection, Issue, IssueConnection, LinearDocument } from '@linear/sdk';

type CycleCreateInput = LinearDocument.CycleCreateInput;
type CycleUpdateInput = LinearDocument.CycleUpdateInput;
type LinearCycleFilter = LinearDocument.CycleFilter;
type LinearIssueFilter = LinearDocument.IssueFilter;

import { linearClient } from '@atoms/client/linear-client';
import { logger } from '@atoms/shared/logger';
import { NotFoundError, ValidationError, Pagination } from '@atoms/types/common';
import { CycleCreate, CycleUpdate, CycleFilter, CycleProgress } from './schemas';
import { IssueFilter } from '@features/issue/schemas';

export class CycleService {
  private client = linearClient.getClient();

  async create(data: CycleCreate): Promise<Cycle> {
    try {
      logger.debug('Creating cycle', data);

      // Check for overlapping cycles within the same team
      await this.validateNonOverlapping(data.teamId, data.startsAt, data.endsAt);

      const input: CycleCreateInput = {
        name: data.name,
        teamId: data.teamId,
        startsAt: new Date(data.startsAt),
        endsAt: new Date(data.endsAt),
        description: data.description,
      };

      const payload = await this.client.createCycle(input);

      if (!payload.success || !payload.cycle) {
        throw new ValidationError('Failed to create cycle');
      }

      const cycle = await payload.cycle;
      logger.success(`Cycle created: ${cycle.name}`);

      return cycle;
    } catch (error) {
      logger.error('Failed to create cycle', error);
      throw error;
    }
  }

  async get(id: string): Promise<Cycle | null> {
    try {
      logger.debug(`Fetching cycle: ${id}`);
      const cycle = await this.client.cycle(id);
      return cycle;
    } catch (error) {
      logger.debug(`Cycle not found: ${id}`);
      return null;
    }
  }

  async update(id: string, data: CycleUpdate): Promise<Cycle> {
    try {
      logger.debug(`Updating cycle: ${id}`, data);

      const cycle = await this.get(id);
      if (!cycle) {
        throw new NotFoundError('Cycle', id);
      }

      // If updating dates, check for overlapping cycles
      if (data.startsAt || data.endsAt) {
        const startDate = data.startsAt || cycle.startsAt.toISOString();
        const endDate = data.endsAt || cycle.endsAt.toISOString();
        const team = cycle.team ? await cycle.team : null;
        if (!team) {
          throw new NotFoundError('Team for cycle', id);
        }

        await this.validateNonOverlapping(team.id, startDate, endDate, id);
      }

      const input: CycleUpdateInput = {
        name: data.name,
        description: data.description,
        startsAt: data.startsAt ? new Date(data.startsAt) : undefined,
        endsAt: data.endsAt ? new Date(data.endsAt) : undefined,
      };

      const payload = await this.client.updateCycle(id, input);

      if (!payload.success || !payload.cycle) {
        throw new ValidationError('Failed to update cycle');
      }

      const updatedCycle = await payload.cycle;
      logger.success(`Cycle updated: ${updatedCycle.name}`);

      return updatedCycle;
    } catch (error) {
      logger.error(`Failed to update cycle ${id}`, error);
      throw error;
    }
  }

  async archive(id: string): Promise<boolean> {
    try {
      logger.debug(`Archiving cycle: ${id}`);

      const cycle = await this.get(id);
      if (!cycle) {
        throw new NotFoundError('Cycle', id);
      }

      const payload = await this.client.archiveCycle(id);

      if (!payload.success) {
        throw new ValidationError('Failed to archive cycle');
      }

      logger.success(`Cycle archived: ${id}`);
      return true;
    } catch (error) {
      logger.error(`Failed to archive cycle ${id}`, error);
      throw error;
    }
  }

  async list(filter?: CycleFilter, pagination?: Pagination): Promise<CycleConnection> {
    try {
      logger.debug('Listing cycles', { filter, pagination });

      const linearFilter: LinearCycleFilter = {};

      if (filter) {
        if (filter.teamId) {
          linearFilter.team = { id: { eq: filter.teamId } };
        }
      }

      const cycles = await this.client.cycles({
        filter: linearFilter,
        includeArchived: filter?.includeArchived,
        first: pagination?.first,
        after: pagination?.after,
        before: pagination?.before,
        last: pagination?.last,
      });

      return cycles;
    } catch (error) {
      logger.error('Failed to list cycles', error);
      throw error;
    }
  }

  async getActive(teamId: string): Promise<Cycle | null> {
    try {
      logger.debug(`Getting active cycle for team: ${teamId}`);

      const cycles = await this.client.cycles({
        filter: {
          team: { id: { eq: teamId } },
        },
        includeArchived: false,
      });

      const cycleNodes = await cycles.nodes;
      const now = new Date();

      // Find cycle where current time is between start and end dates
      const activeCycle = cycleNodes.find((cycle) => {
        const startDate = new Date(cycle.startsAt);
        const endDate = new Date(cycle.endsAt);
        return now >= startDate && now <= endDate;
      });

      return activeCycle || null;
    } catch (error) {
      logger.error(`Failed to get active cycle for team ${teamId}`, error);
      throw error;
    }
  }

  async getUpcoming(teamId: string): Promise<CycleConnection> {
    try {
      logger.debug(`Getting upcoming cycles for team: ${teamId}`);

      const cycles = await this.client.cycles({
        filter: {
          team: { id: { eq: teamId } },
        },
        includeArchived: false,
      });

      const cycleNodes = await cycles.nodes;
      const now = new Date();

      // Filter cycles that start in the future
      const upcomingCycles = cycleNodes.filter((cycle) => {
        const startDate = new Date(cycle.startsAt);
        return startDate > now;
      });

      // Return as connection format (simplified mock for now)
      return {
        ...cycles,
        nodes: upcomingCycles,
      } as CycleConnection;
    } catch (error) {
      logger.error(`Failed to get upcoming cycles for team ${teamId}`, error);
      throw error;
    }
  }

  async getCompleted(teamId: string): Promise<CycleConnection> {
    try {
      logger.debug(`Getting completed cycles for team: ${teamId}`);

      const cycles = await this.client.cycles({
        filter: {
          team: { id: { eq: teamId } },
        },
        includeArchived: false,
      });

      const cycleNodes = await cycles.nodes;

      // Filter cycles that have a completedAt date
      const completedCycles = cycleNodes.filter((cycle) => cycle.completedAt);

      // Return as connection format (simplified mock for now)
      return {
        ...cycles,
        nodes: completedCycles,
      } as CycleConnection;
    } catch (error) {
      logger.error(`Failed to get completed cycles for team ${teamId}`, error);
      throw error;
    }
  }

  async getIssues(cycleId: string, filter?: IssueFilter): Promise<IssueConnection> {
    try {
      logger.debug(`Getting issues for cycle: ${cycleId}`);

      const linearFilter: LinearIssueFilter = {
        cycle: { id: { eq: cycleId } },
      };

      if (filter) {
        if (filter.state) {
          linearFilter.state = { type: { eq: filter.state } };
        }
        if (filter.assigneeId) {
          linearFilter.assignee = { id: { eq: filter.assigneeId } };
        }
      }

      const issues = await this.client.issues({
        filter: linearFilter,
        includeArchived: false,
      });

      return issues;
    } catch (error) {
      logger.error(`Failed to get issues for cycle ${cycleId}`, error);
      throw error;
    }
  }

  async addIssue(cycleId: string, issueId: string): Promise<Issue> {
    try {
      logger.debug(`Adding issue ${issueId} to cycle ${cycleId}`);

      try {
        const issue = await this.client.issue(issueId);
        if (!issue) {
          throw new NotFoundError('Issue', issueId);
        }
      } catch (error) {
        throw new NotFoundError('Issue', issueId);
      }

      const payload = await this.client.updateIssue(issueId, {
        cycleId: cycleId,
      });

      if (!payload.success || !payload.issue) {
        throw new ValidationError('Failed to add issue to cycle');
      }

      const updatedIssue = await payload.issue;
      logger.success(`Issue added to cycle: ${updatedIssue.identifier}`);

      return updatedIssue;
    } catch (error) {
      logger.error(`Failed to add issue ${issueId} to cycle ${cycleId}`, error);
      throw error;
    }
  }

  async removeIssue(cycleId: string, issueId: string): Promise<Issue> {
    try {
      logger.debug(`Removing issue ${issueId} from cycle ${cycleId}`);

      try {
        const issue = await this.client.issue(issueId);
        if (!issue) {
          throw new NotFoundError('Issue', issueId);
        }
      } catch (error) {
        throw new NotFoundError('Issue', issueId);
      }

      const payload = await this.client.updateIssue(issueId, {
        cycleId: null,
      });

      if (!payload.success || !payload.issue) {
        throw new ValidationError('Failed to remove issue from cycle');
      }

      const updatedIssue = await payload.issue;
      logger.success(`Issue removed from cycle: ${updatedIssue.identifier}`);

      return updatedIssue;
    } catch (error) {
      logger.error(`Failed to remove issue ${issueId} from cycle ${cycleId}`, error);
      throw error;
    }
  }

  async getProgress(cycleId: string): Promise<CycleProgress> {
    try {
      logger.debug(`Calculating progress for cycle: ${cycleId}`);

      const cycle = await this.get(cycleId);
      if (!cycle) {
        throw new NotFoundError('Cycle', cycleId);
      }

      const issues = await this.getIssues(cycleId);
      const issueNodes = await issues.nodes;

      let completedPoints = 0;
      let totalPoints = 0;
      let completedIssues = 0;
      const totalIssues = issueNodes.length;

      for (const issue of issueNodes) {
        const estimate = issue.estimate || 0;
        totalPoints += estimate;

        if (issue.completedAt) {
          completedPoints += estimate;
          completedIssues++;
        }
      }

      const percentComplete =
        totalPoints > 0 ? Math.round((completedPoints / totalPoints) * 100) : 0;

      return {
        completedPoints,
        totalPoints,
        percentComplete,
        completedIssues,
        totalIssues,
      };
    } catch (error) {
      logger.error(`Failed to calculate progress for cycle ${cycleId}`, error);
      throw error;
    }
  }

  async getVelocity(cycleId: string): Promise<number> {
    try {
      logger.debug(`Calculating velocity for cycle: ${cycleId}`);

      const cycle = await this.get(cycleId);
      if (!cycle) {
        throw new NotFoundError('Cycle', cycleId);
      }

      const issues = await this.getIssues(cycleId);
      const issueNodes = await issues.nodes;

      let completedPoints = 0;
      for (const issue of issueNodes) {
        if (issue.completedAt && issue.estimate) {
          completedPoints += issue.estimate;
        }
      }

      // Calculate cycle duration in weeks
      const startDate = new Date(cycle.startsAt);
      const endDate = new Date(cycle.endsAt);
      const durationMs = endDate.getTime() - startDate.getTime();
      const durationWeeks = durationMs / (1000 * 60 * 60 * 24 * 7);

      // Velocity = completed points per week
      const velocity = durationWeeks > 0 ? completedPoints / durationWeeks : 0;

      return velocity;
    } catch (error) {
      logger.error(`Failed to calculate velocity for cycle ${cycleId}`, error);
      throw error;
    }
  }

  private async validateNonOverlapping(
    teamId: string,
    startsAt: string,
    endsAt: string,
    excludeCycleId?: string,
  ): Promise<void> {
    const existingCycles = await this.client.cycles({
      filter: {
        team: { id: { eq: teamId } },
      },
      includeArchived: false,
    });

    const cycleNodes = await existingCycles.nodes;
    const newStart = new Date(startsAt);
    const newEnd = new Date(endsAt);

    for (const cycle of cycleNodes) {
      if (excludeCycleId && cycle.id === excludeCycleId) {
        continue; // Skip the cycle being updated
      }

      const existingStart = new Date(cycle.startsAt);
      const existingEnd = new Date(cycle.endsAt);

      // Check for overlap: new cycle starts before existing ends AND new cycle ends after existing starts
      const hasOverlap = newStart < existingEnd && newEnd > existingStart;

      if (hasOverlap) {
        throw new ValidationError(`Cycle dates overlap with existing cycle: ${cycle.name}`);
      }
    }
  }
}

import { Issue, IssueConnection, LinearDocument } from '@linear/sdk';

type IssueCreateInput = LinearDocument.IssueCreateInput;
type IssueUpdateInput = LinearDocument.IssueUpdateInput;
type LinearIssueFilter = LinearDocument.IssueFilter;
import { linearClient } from '@atoms/client/linear-client';
import { logger } from '@atoms/shared/logger';
import {
  NotFoundError,
  ValidationError,
  OperationResult,
  BatchOperationResult,
  Pagination,
} from '@atoms/types/common';
import { IssueCreate, IssueUpdate, IssueFilter, IssueBulkUpdate } from './schemas';

export class IssueService {
  private client = linearClient.getClient();

  async create(data: IssueCreate): Promise<Issue> {
    try {
      logger.debug('Creating issue', data);

      const input: IssueCreateInput = {
        title: data.title,
        description: data.description,
        teamId: data.teamId,
        assigneeId: data.assigneeId,
        priority: data.priority,
        estimate: data.estimate,
        labelIds: data.labelIds,
        projectId: data.projectId,
        cycleId: data.cycleId,
        parentId: data.parentId,
        dueDate: data.dueDate,
      };

      const payload = await this.client.createIssue(input);

      if (!payload.success || !payload.issue) {
        throw new ValidationError('Failed to create issue');
      }

      const issue = await payload.issue;
      logger.success(`Issue created: ${issue.identifier}`);

      return issue;
    } catch (error) {
      logger.error('Failed to create issue', error);
      throw error;
    }
  }

  async get(id: string): Promise<Issue | null> {
    try {
      logger.debug(`Fetching issue: ${id}`);
      const issue = await this.client.issue(id);
      return issue;
    } catch (error) {
      logger.debug(`Issue not found: ${id}`);
      return null;
    }
  }

  async getByIdentifier(identifier: string): Promise<Issue | null> {
    try {
      logger.debug(`Fetching issue by identifier: ${identifier}`);

      const issues = await this.client.issues({
        filter: {
          searchableContent: { contains: identifier },
        },
        first: 1,
      });

      const nodes = await issues.nodes;
      if (nodes.length === 0) {
        return null;
      }

      const issue = nodes.find((i) => i.identifier === identifier);
      return issue || null;
    } catch (error) {
      logger.debug(`Issue not found: ${identifier}`);
      return null;
    }
  }

  async update(id: string, data: IssueUpdate): Promise<Issue> {
    try {
      logger.debug(`Updating issue: ${id}`, data);

      const issue = await this.get(id);
      if (!issue) {
        throw new NotFoundError('Issue', id);
      }

      const input: IssueUpdateInput = {
        title: data.title,
        description: data.description,
        assigneeId: data.assigneeId,
        priority: data.priority,
        estimate: data.estimate,
        labelIds: data.labelIds,
        projectId: data.projectId,
        cycleId: data.cycleId,
        parentId: data.parentId,
        dueDate: data.dueDate,
        stateId: data.stateId,
      };

      const payload = await this.client.updateIssue(id, input);

      if (!payload.success || !payload.issue) {
        throw new ValidationError('Failed to update issue');
      }

      const updatedIssue = await payload.issue;
      logger.success(`Issue updated: ${updatedIssue.identifier}`);

      return updatedIssue;
    } catch (error) {
      logger.error(`Failed to update issue ${id}`, error);
      throw error;
    }
  }

  async delete(id: string): Promise<boolean> {
    try {
      logger.debug(`Deleting issue: ${id}`);

      const issue = await this.get(id);
      if (!issue) {
        throw new NotFoundError('Issue', id);
      }

      const payload = await this.client.deleteIssue(id);

      if (!payload.success) {
        throw new ValidationError('Failed to delete issue');
      }

      logger.success(`Issue deleted: ${id}`);
      return true;
    } catch (error) {
      logger.error(`Failed to delete issue ${id}`, error);
      throw error;
    }
  }

  async archive(id: string): Promise<boolean> {
    try {
      logger.debug(`Archiving issue: ${id}`);

      const issue = await this.get(id);
      if (!issue) {
        throw new NotFoundError('Issue', id);
      }

      const payload = await this.client.archiveIssue(id);

      if (!payload.success) {
        throw new ValidationError('Failed to archive issue');
      }

      logger.success(`Issue archived: ${id}`);
      return true;
    } catch (error) {
      logger.error(`Failed to archive issue ${id}`, error);
      throw error;
    }
  }

  async list(filter?: IssueFilter, pagination?: Pagination): Promise<IssueConnection> {
    try {
      logger.debug('Listing issues', { filter, pagination });

      const linearFilter: LinearIssueFilter = {};

      if (filter) {
        if (filter.teamId) {
          linearFilter.team = { id: { eq: filter.teamId } };
        }
        if (filter.assigneeId) {
          linearFilter.assignee = { id: { eq: filter.assigneeId } };
        }
        if (filter.creatorId) {
          linearFilter.creator = { id: { eq: filter.creatorId } };
        }
        if (filter.projectId) {
          linearFilter.project = { id: { eq: filter.projectId } };
        }
        if (filter.cycleId) {
          linearFilter.cycle = { id: { eq: filter.cycleId } };
        }
        if (filter.priority !== undefined) {
          linearFilter.priority = { eq: filter.priority };
        }
        if (filter.state) {
          linearFilter.state = { type: { eq: filter.state } };
        }
        if (filter.searchQuery) {
          linearFilter.searchableContent = { contains: filter.searchQuery };
        }
      }

      const issues = await this.client.issues({
        filter: linearFilter,
        includeArchived: filter?.includeArchived,
        first: pagination?.first,
        after: pagination?.after,
        before: pagination?.before,
        last: pagination?.last,
      });

      return issues;
    } catch (error) {
      logger.error('Failed to list issues', error);
      throw error;
    }
  }

  async bulkUpdate(data: IssueBulkUpdate): Promise<BatchOperationResult<Issue>> {
    const results: BatchOperationResult<Issue> = {
      success: false,
      succeeded: [],
      failed: [],
      totalCount: data.issueIds.length,
      successCount: 0,
      failureCount: 0,
    };

    for (const issueId of data.issueIds) {
      try {
        const updated = await this.update(issueId, data.update);
        results.succeeded.push(updated);
        results.successCount++;
      } catch (error: any) {
        results.failed.push({
          item: issueId,
          error: error.message || 'Unknown error',
        });
        results.failureCount++;
      }
    }

    results.success = results.failureCount === 0;

    logger.info(`Bulk update completed: ${results.successCount}/${results.totalCount} succeeded`);

    return results;
  }

  async addComment(issueId: string, body: string): Promise<boolean> {
    try {
      logger.debug(`Adding comment to issue ${issueId}`);

      const payload = await this.client.createComment({
        issueId,
        body,
      });

      if (!payload.success) {
        throw new ValidationError('Failed to add comment');
      }

      logger.success('Comment added');
      return true;
    } catch (error) {
      logger.error(`Failed to add comment to issue ${issueId}`, error);
      throw error;
    }
  }

  async addLabels(issueId: string, labelIds: string[]): Promise<Issue> {
    try {
      const issue = await this.get(issueId);
      if (!issue) {
        throw new NotFoundError('Issue', issueId);
      }

      const currentLabelIds = (await issue.labels()).nodes.map((l) => l.id);
      const newLabelIds = [...new Set([...currentLabelIds, ...labelIds])];

      return await this.update(issueId, { labelIds: newLabelIds });
    } catch (error) {
      logger.error(`Failed to add labels to issue ${issueId}`, error);
      throw error;
    }
  }

  async removeLabels(issueId: string, labelIds: string[]): Promise<Issue> {
    try {
      const issue = await this.get(issueId);
      if (!issue) {
        throw new NotFoundError('Issue', issueId);
      }

      const currentLabelIds = (await issue.labels()).nodes.map((l) => l.id);
      const newLabelIds = currentLabelIds.filter((id) => !labelIds.includes(id));

      return await this.update(issueId, { labelIds: newLabelIds });
    } catch (error) {
      logger.error(`Failed to remove labels from issue ${issueId}`, error);
      throw error;
    }
  }
}

import {
