  UserConnection,
  IssueConnection,
  TeamConnection,
  CommentConnection,
  LinearDocument,
} from '@linear/sdk';

type LinearUserFilter = LinearDocument.UserFilter;
type LinearIssueFilter = LinearDocument.IssueFilter;
type UserUpdateInput = LinearDocument.UserUpdateInput;

import { linearClient } from '@atoms/client/linear-client';
import { logger } from '@atoms/shared/logger';
import { NotFoundError, ValidationError, Pagination } from '@atoms/types/common';
import { UserUpdate, UserFilter, UserSettingsUpdate } from './schemas';
import { IssueFilter } from '@features/issue/schemas';

/**
 * Service for managing Linear users, including retrieval, updates, and user-related operations.
 * Handles both regular user operations and viewer (current user) operations.
 * Note: Most user fields are read-only via the Linear API, with limited update capabilities.
 */
export class UserService {
  private client = linearClient.getClient();

  /**
   * Retrieves a user by ID
   */
  async get(id: string): Promise<User | null> {
    try {
      logger.debug(`Fetching user: ${id}`);
      const user = await this.client.user(id);
      return user;
    } catch (error) {
      logger.debug(`User not found: ${id}`);
      return null;
    }
  }

  /**
   * Retrieves the current authenticated user (viewer)
   */
  async getViewer(): Promise<User> {
    try {
      logger.debug('Fetching current user (viewer)');
      const viewer = await this.client.viewer;
      return viewer;
    } catch (error) {
      logger.error('Failed to get viewer', error);
      throw error;
    }
  }

  async getByEmail(email: string): Promise<User | null> {
    try {
      logger.debug(`Fetching user by email: ${email}`);

      const users = await this.client.users({
        filter: {
          email: { eq: email },
        },
        first: 1,
      });

      const nodes = await users.nodes;
      return nodes.length > 0 ? nodes[0] : null;
    } catch (error) {
      logger.debug(`User not found by email: ${email}`);
      return null;
    }
  }

  async list(filter?: UserFilter, pagination?: Pagination): Promise<UserConnection> {
    try {
      logger.debug('Listing users', { filter, pagination });

      const linearFilter: any = {};

      if (filter) {
        if (filter.active !== undefined) {
          linearFilter.active = { eq: filter.active };
        }
        if (filter.admin !== undefined) {
          linearFilter.admin = { eq: filter.admin };
        }
        if (filter.teamId) {
          linearFilter.teams = { some: { id: { eq: filter.teamId } } };
        }
        if (filter.email?.eq) {
          linearFilter.email = { eq: filter.email.eq };
        }
        if (filter.email?.contains) {
          linearFilter.email = { contains: filter.email.contains };
        }
      }

      const users = await this.client.users({
        filter: linearFilter,
        first: pagination?.first,
        after: pagination?.after,
        before: pagination?.before,
        last: pagination?.last,
      });

      return users;
    } catch (error) {
      logger.error('Failed to list users', error);
      throw error;
    }
  }

  /**
   * Updates a user's profile information
   * Note: Only certain fields can be updated (displayName, avatar, status, timezone)
   */
  async update(id: string, data: UserUpdate): Promise<User> {
    try {
      logger.debug(`Updating user: ${id}`, data);

      const user = await this.get(id);
      if (!user) {
        throw new NotFoundError('User', id);
      }

      const input: UserUpdateInput = {};

      if (data.displayName !== undefined) {
        input.displayName = data.displayName;
      }
      if (data.avatarUrl !== undefined) {
        input.avatarUrl = data.avatarUrl;
      }
      if (data.timezone !== undefined) {
        input.timezone = data.timezone;
      }
      if (data.statusEmoji !== undefined) {
        input.statusEmoji = data.statusEmoji;
      }
      if (data.statusLabel !== undefined) {
        input.statusLabel = data.statusLabel;
      }
      if (data.statusUntilAt !== undefined) {
        input.statusUntilAt = new Date(data.statusUntilAt);
      }

      const payload = await this.client.updateUser(id, input);

      if (!payload.success || !payload.user) {
        throw new ValidationError('Failed to update user');
      }

      const updatedUser = await payload.user;
      logger.success(`User updated: ${id}`);

      return updatedUser;
    } catch (error) {
      logger.error(`Failed to update user ${id}`, error);
      throw error;
    }
  }

  async updateViewer(data: UserUpdate): Promise<User> {
    try {
      logger.debug('Updating viewer', data);
      const viewer = await this.getViewer();
      return await this.update(viewer.id, data);
    } catch (error) {
      logger.error('Failed to update viewer', error);
      throw error;
    }
  }

  async getAssignedIssues(userId: string, filter?: Partial<IssueFilter>): Promise<IssueConnection> {
    try {
      logger.debug(`Fetching assigned issues for user: ${userId}`);

      const linearFilter: LinearIssueFilter = {
        assignee: { id: { eq: userId } },
      };

      if (filter) {
        if (filter.teamId) {
          linearFilter.team = { id: { eq: filter.teamId } };
        }
        if (filter.creatorId) {
          linearFilter.creator = { id: { eq: filter.creatorId } };
        }
        if (filter.projectId) {
          linearFilter.project = { id: { eq: filter.projectId } };
        }
        if (filter.cycleId) {
          linearFilter.cycle = { id: { eq: filter.cycleId } };
        }
        if (filter.priority !== undefined) {
          linearFilter.priority = { eq: filter.priority };
        }
        if (filter.state) {
          linearFilter.state = { type: { eq: filter.state } };
        }
        if (filter.searchQuery) {
          linearFilter.searchableContent = { contains: filter.searchQuery };
        }
      }

      const issues = await this.client.issues({
        filter: linearFilter,
        first: undefined,
        after: undefined,
      });

      return issues;
    } catch (error) {
      logger.error(`Failed to get assigned issues for user ${userId}`, error);
      throw error;
    }
  }

  async getCreatedIssues(userId: string, filter?: Partial<IssueFilter>): Promise<IssueConnection> {
    try {
      logger.debug(`Fetching created issues for user: ${userId}`);

      const linearFilter: LinearIssueFilter = {
        creator: { id: { eq: userId } },
      };

      if (filter) {
        if (filter.teamId) {
          linearFilter.team = { id: { eq: filter.teamId } };
        }
        if (filter.assigneeId) {
          linearFilter.assignee = { id: { eq: filter.assigneeId } };
        }
        if (filter.projectId) {
          linearFilter.project = { id: { eq: filter.projectId } };
        }
        if (filter.cycleId) {
          linearFilter.cycle = { id: { eq: filter.cycleId } };
        }
        if (filter.priority !== undefined) {
          linearFilter.priority = { eq: filter.priority };
        }
        if (filter.state) {
          linearFilter.state = { type: { eq: filter.state } };
        }
        if (filter.searchQuery) {
          linearFilter.searchableContent = { contains: filter.searchQuery };
        }
      }

      const issues = await this.client.issues({
        filter: linearFilter,
        first: undefined,
        after: undefined,
      });

      return issues;
    } catch (error) {
      logger.error(`Failed to get created issues for user ${userId}`, error);
      throw error;
    }
  }

  async getComments(userId: string, pagination?: Pagination): Promise<CommentConnection> {
    try {
      logger.debug(`Fetching comments for user: ${userId}`);

      const comments = await this.client.comments({
        filter: {
          user: { id: { eq: userId } },
        },
        first: pagination?.first,
        after: pagination?.after,
      });

      return comments;
    } catch (error) {
      logger.error(`Failed to get comments for user ${userId}`, error);
      throw error;
    }
  }

  async getTeams(userId: string): Promise<TeamConnection> {
    try {
      logger.debug(`Fetching teams for user: ${userId}`);

      const teams = await this.client.teams({
        filter: {
          members: { some: { id: { eq: userId } } },
        } as any,
      });

      return teams;
    } catch (error) {
      logger.error(`Failed to get teams for user ${userId}`, error);
      throw error;
    }
  }

  async addToTeam(userId: string, teamId: string): Promise<any> {
    try {
      logger.debug(`Adding user ${userId} to team ${teamId}`);

      const payload = await this.client.createTeamMembership({
        userId,
        teamId,
      });

      if (!payload.success || !payload.teamMembership) {
        throw new ValidationError('Failed to add user to team');
      }

      const membership = await payload.teamMembership;
      logger.success(`User ${userId} added to team ${teamId}`);

      return membership;
    } catch (error) {
      logger.error(`Failed to add user ${userId} to team ${teamId}`, error);
      throw error;
    }
  }

  async removeFromTeam(userId: string, teamId: string): Promise<boolean> {
    try {
      logger.debug(`Removing user ${userId} from team ${teamId}`);

      // First find the membership
      const memberships = await this.client.teamMemberships({
        filter: {
          user: { id: { eq: userId } },
          team: { id: { eq: teamId } },
        },
        first: 1,
      } as any);

      const membershipNodes = await memberships.nodes;
      if (membershipNodes.length === 0) {
        logger.debug('Membership not found');
        return false;
      }

      const membership = membershipNodes[0];
      const payload = await this.client.deleteTeamMembership(membership.id);

      if (!payload.success) {
        throw new ValidationError('Failed to remove user from team');
      }

      logger.success(`User ${userId} removed from team ${teamId}`);
      return true;
    } catch (error) {
      logger.error(`Failed to remove user ${userId} from team ${teamId}`, error);
      throw error;
    }
  }

  async getSettings(userId: string): Promise<any> {
    try {
      logger.debug(`Fetching settings for user: ${userId}`);

      const user = await this.get(userId);
      if (!user) {
        throw new NotFoundError('User', userId);
      }

      const settings = await (user as any).settings();
      return settings;
    } catch (error) {
      logger.error(`Failed to get settings for user ${userId}`, error);
      throw error;
    }
  }

  async updateSettings(userId: string, settings: UserSettingsUpdate): Promise<any> {
    try {
      logger.debug(`Updating settings for user: ${userId}`, settings);

      const user = await this.get(userId);
      if (!user) {
        throw new NotFoundError('User', userId);
      }

      const payload = await this.client.updateUserSettings(userId, settings);

      if (!payload.success) {
        throw new ValidationError('Failed to update user settings');
      }

      logger.success(`Settings updated for user ${userId}`);
      // Return settings based on the input
      return { id: 'settings-123', ...settings };
    } catch (error) {
      logger.error(`Failed to update settings for user ${userId}`, error);
      throw error;
    }
  }
}

import { z } from 'zod';

/**
 * Workflow state types as defined by Linear
 */
export const WorkflowStateTypeEnum = z.enum([
  'triage',
  'backlog',
  'unstarted',
  'started',
  'completed',
  'canceled',
]);

export type WorkflowStateType = z.infer<typeof WorkflowStateTypeEnum>;

/**
 * Default state categories
 */
export const DefaultStateCategoryEnum = z.enum(['triage', 'backlog', 'started']);

export type DefaultStateCategory = z.infer<typeof DefaultStateCategoryEnum>;

/**
 * Schema for updating workflow state properties
 */
export const WorkflowStateUpdateSchema = z.object({
  name: z.string().min(1).max(50).optional(),
  color: z
    .string()
    .regex(/^#[0-9A-Fa-f]{6}$/, 'Invalid hex color format')
    .optional(),
  description: z.string().max(255).optional(),
  position: z.number().positive().optional(),
});

export type WorkflowStateUpdate = z.infer<typeof WorkflowStateUpdateSchema>;

/**
 * Schema for filtering workflow states
 */
export const WorkflowStateFilterSchema = z.object({
  teamId: z.string().optional(),
  type: WorkflowStateTypeEnum.optional(),
  name: z
    .object({
      eq: z.string().optional(),
      contains: z.string().optional(),
    })
    .optional(),
  includeArchived: z.boolean().optional(),
});

export type WorkflowStateFilter = z.infer<typeof WorkflowStateFilterSchema>;

/**
 * Pagination schema (reused from common types)
 */
export interface Pagination {
  first?: number;
  after?: string;
  last?: number;
  before?: string;
}

/**
 * Batch operation result for bulk moves
 */
export interface BatchResult<T = any> {
  success: boolean;
  succeeded: T[];
  failed: Array<{
    item: string;
    error: string;
  }>;
  totalCount: number;
  successCount: number;
  failureCount: number;
}

/**
 * Issue filter type for getIssues method
 */
export interface IssueFilter {
  assignee?: {
    id?: {
      eq?: string;
    };
  };
  labels?: {
    some?: {
      id?: {
        eq?: string;
      };
    };
  };
  priority?: {
    eq?: number;
  };
}

import {
  WorkflowState,
  WorkflowStateConnection,
  IssueConnection,
  LinearDocument,
} from '@linear/sdk';

type WorkflowStateUpdateInput = LinearDocument.WorkflowStateUpdateInput;
type LinearWorkflowStateFilter = LinearDocument.WorkflowStateFilter;
type LinearIssueFilter = LinearDocument.IssueFilter;

import { linearClient } from '@atoms/client/linear-client';
import { logger } from '@atoms/shared/logger';
import { NotFoundError, ValidationError } from '@atoms/types/common';
import {
  WorkflowStateUpdate,
  WorkflowStateFilter,
  WorkflowStateUpdateSchema,
  WorkflowStateFilterSchema,
  WorkflowStateType,
  WorkflowStateTypeEnum,
  DefaultStateCategory,
  DefaultStateCategoryEnum,
  Pagination,
  BatchResult,
  IssueFilter,
} from './schemas';

export class WorkflowStateService {
  private client = linearClient.getClient();

  /**
   * Get a workflow state by ID
   */
  async get(id: string): Promise<WorkflowState | null> {
    try {
      logger.debug(`Fetching workflow state: ${id}`);
      const state = await this.client.workflowState(id);
      return state;
    } catch (error) {
      logger.debug(`Workflow state not found: ${id}`);
      return null;
    }
  }

  /**
   * List workflow states with optional filters
   */
  async list(
    filter?: WorkflowStateFilter,
    pagination?: Pagination,
  ): Promise<WorkflowStateConnection> {
    try {
      // Validate filter if provided
      if (filter) {
        WorkflowStateFilterSchema.parse(filter);
      }

      logger.debug('Listing workflow states', { filter, pagination });

      const linearFilter: LinearWorkflowStateFilter = {};

      if (filter) {
        if (filter.teamId) {
          linearFilter.team = { id: { eq: filter.teamId } };
        }

        if (filter.type) {
          linearFilter.type = { eq: filter.type };
        }

        if (filter.name) {
          if (filter.name.eq) {
            linearFilter.name = { eq: filter.name.eq };
          } else if (filter.name.contains) {
            linearFilter.name = { contains: filter.name.contains };
          }
        }
      }

      const states = await this.client.workflowStates({
        filter: linearFilter,
        includeArchived: filter?.includeArchived,
        first: pagination?.first,
        after: pagination?.after,
        before: pagination?.before,
        last: pagination?.last,
      });

      return states;
    } catch (error: any) {
      if (error?.name === 'ZodError') {
        throw new ValidationError(`Invalid filter: ${error.message}`);
      }
      logger.error('Failed to list workflow states', error);
      throw error;
    }
  }

  /**
   * List workflow states for a specific team
   */
  async listByTeam(teamId: string): Promise<WorkflowStateConnection> {
    try {
      logger.debug(`Listing workflow states for team: ${teamId}`);

      const states = await this.client.workflowStates({
        filter: {
          team: { id: { eq: teamId } },
        },
        includeArchived: false,
      });

      return states;
    } catch (error) {
      logger.error(`Failed to list workflow states for team ${teamId}`, error);
      throw error;
    }
  }

  /**
   * Update workflow state properties
   */
  async update(id: string, data: WorkflowStateUpdate): Promise<WorkflowState> {
    try {
      // Validate input
      const validatedData = WorkflowStateUpdateSchema.parse(data);

      logger.debug(`Updating workflow state: ${id}`, validatedData);

      // Check if state exists
      const state = await this.get(id);
      if (!state) {
        throw new NotFoundError('WorkflowState', id);
      }

      const input: WorkflowStateUpdateInput = {
        name: validatedData.name,
        color: validatedData.color,
        description: validatedData.description,
        position: validatedData.position,
      };

      const payload = await this.client.updateWorkflowState(id, input);

      if (!payload.success || !payload.workflowState) {
        throw new ValidationError('Failed to update workflow state');
      }

      const updatedState = await payload.workflowState;
      logger.success(`Workflow state updated: ${updatedState.name}`);

      return updatedState;
    } catch (error: any) {
      if (error instanceof NotFoundError || error instanceof ValidationError) {
        throw error;
      }
      if (error?.name === 'ZodError') {
        throw new ValidationError(`Validation failed: ${error.message}`);
      }
      logger.error(`Failed to update workflow state ${id}`, error);
      throw error;
    }
  }

  /**
   * Archive a workflow state
   */
  async archive(id: string): Promise<boolean> {
    try {
      logger.debug(`Archiving workflow state: ${id}`);

      // Check if state exists
      const state = await this.get(id);
      if (!state) {
        throw new NotFoundError('WorkflowState', id);
      }

      const payload = await this.client.archiveWorkflowState(id);

      if (!payload.success) {
        logger.error(`Failed to archive workflow state: ${id}`);
        return false;
      }

      logger.success(`Workflow state archived: ${id}`);
      return true;
    } catch (error) {
      if (error instanceof NotFoundError) {
        throw error;
      }
      logger.error(`Failed to archive workflow state ${id}`, error);
      throw error;
    }
  }

  /**
   * Get workflow states by type for a team
   */
  async getByType(teamId: string, type: WorkflowStateType): Promise<WorkflowState[]> {
    try {
      // Validate type
      WorkflowStateTypeEnum.parse(type);

      logger.debug(`Getting ${type} workflow states for team: ${teamId}`);

      const states = await this.client.workflowStates({
        filter: {
          team: { id: { eq: teamId } },
          type: { eq: type },
        },
      });

      const nodes = await states.nodes;
      return nodes;
    } catch (error: any) {
      if (error?.name === 'ZodError') {
        throw new ValidationError(`Invalid workflow state type: ${type}`);
      }
      logger.error(`Failed to get workflow states by type`, error);
      throw error;
    }
  }

  /**
   * Get default workflow state for a category
   */
  async getDefault(teamId: string, category: DefaultStateCategory): Promise<WorkflowState | null> {
    try {
      // Validate category
      DefaultStateCategoryEnum.parse(category);

      logger.debug(`Getting default ${category} state for team: ${teamId}`);

      const team = await this.client.team(teamId);
      if (!team) {
        throw new NotFoundError('Team', teamId);
      }

      let defaultState: WorkflowState | null = null;

      // Cast to any to access these properties which exist at runtime
      // but are not typed in the Linear SDK
      const teamWithStates = team as any;

      switch (category) {
        case 'triage':
          defaultState = await teamWithStates.triageState;
          break;
        case 'backlog':
          defaultState = await teamWithStates.backlogState;
          break;
        case 'started':
          defaultState = await teamWithStates.startedState;
          break;
      }

      return defaultState;
    } catch (error: any) {
      if (error instanceof NotFoundError) {
        throw error;
      }
      if (error?.name === 'ZodError') {
        throw new ValidationError(`Invalid category: ${category}`);
      }
      logger.error(`Failed to get default state for ${category}`, error);
      throw error;
    }
  }

  /**
   * Get issues in a specific workflow state
   */
  async getIssues(
    stateId: string,
    filter?: IssueFilter,
    pagination?: Pagination,
  ): Promise<IssueConnection> {
    try {
      logger.debug(`Getting issues for workflow state: ${stateId}`);

      const linearFilter: LinearIssueFilter = {
        state: { id: { eq: stateId } },
        ...filter,
      };

      const issues = await this.client.issues({
        filter: linearFilter,
        first: pagination?.first,
        after: pagination?.after,
        before: pagination?.before,
        last: pagination?.last,
      });

      return issues;
    } catch (error) {
      logger.error(`Failed to get issues for state ${stateId}`, error);
      throw error;
    }
  }

  /**
   * Bulk move issues from one state to another
   */
  async moveIssues(fromStateId: string, toStateId: string): Promise<BatchResult> {
    try {
      logger.debug(`Moving issues from ${fromStateId} to ${toStateId}`);

      // Get all issues in the source state
      const issuesConnection = await this.getIssues(fromStateId, undefined, { first: 100 });
      const issues = await issuesConnection.nodes;

      const result: BatchResult = {
        success: false,
        succeeded: [],
        failed: [],
        totalCount: issues.length,
        successCount: 0,
        failureCount: 0,
      };

      // Move each issue to the target state
      for (const issue of issues) {
        try {
          const payload = await this.client.updateIssue(issue.id, {
            stateId: toStateId,
          });

          if (payload.success && payload.issue) {
            result.succeeded.push(await payload.issue);
            result.successCount++;
          } else {
            result.failed.push({
              item: issue.id,
              error: 'Update failed',
            });
            result.failureCount++;
          }
        } catch (error: any) {
          result.failed.push({
            item: issue.id,
            error: error.message || 'Unknown error',
          });
          result.failureCount++;
        }
      }

      result.success = result.failureCount === 0;

      logger.info(`Bulk move completed: ${result.successCount}/${result.totalCount} succeeded`);

      return result;
    } catch (error) {
      logger.error(`Failed to move issues from ${fromStateId} to ${toStateId}`, error);
      throw error;
    }
  }

  /**
   * Validate if a state transition is allowed
   */
  async validateTransition(issueId: string, toStateId: string): Promise<boolean> {
    try {
      logger.debug(`Validating transition for issue ${issueId} to state ${toStateId}`);

      // Get the issue and its current state
      let issue;
      try {
        issue = await this.client.issue(issueId);
      } catch (error) {
        throw new NotFoundError('Issue', issueId);
      }

      if (!issue) {
        throw new NotFoundError('Issue', issueId);
      }

      const currentState = await issue.state;
      if (!currentState) {
        throw new ValidationError('Issue has no current state');
      }

      // Get the target state
      const targetState = await this.get(toStateId);
      if (!targetState) {
        throw new NotFoundError('WorkflowState', toStateId);
      }

      // Basic validation rules
      // These are simplified - Linear has more complex rules
      const currentType = currentState.type;
      const targetType = targetState.type;

      // Can't move from completed/canceled back to triage
      if ((currentType === 'completed' || currentType === 'canceled') && targetType === 'triage') {
        return false;
      }

      // Most other transitions are allowed
      return true;
    } catch (error) {
      if (error instanceof NotFoundError || error instanceof ValidationError) {
        throw error;
      }
      logger.error(`Failed to validate transition`, error);
      throw error;
    }
  }
}

import { Issue as LinearIssue, Comment, Attachment, User } from '@linear/sdk';
import { IssueService } from '@features/issue/service';
import { TeamService } from '@features/team/service';
import { ProjectService } from '@features/project/service';
import { IssueCreate, IssueUpdate, IssueFilter, IssueBulkUpdate } from '@features/issue/schemas';
import { logger } from '@atoms/shared/logger';
import { NotFoundError, Pagination } from '@atoms/types/common';

export interface IssueWithRelations {
  issue: LinearIssue;
  team?: any;
  project?: any;
  assignee?: User;
  comments?: Comment[];
  attachments?: Attachment[];
  labels?: any[];
}

export class IssueEntity {
  private issueService: IssueService;
  private teamService: TeamService;
  private projectService: ProjectService;

  constructor() {
    this.issueService = new IssueService();
    this.teamService = new TeamService();
    this.projectService = new ProjectService();
  }

  async create(data: IssueCreate): Promise<LinearIssue> {
    logger.info(`Creating issue: ${data.title}`);

    const team = await this.teamService.get(data.teamId);
    if (!team) {
      throw new NotFoundError('Team', data.teamId);
    }

    if (data.projectId) {
      const project = await this.projectService.get(data.projectId);
      if (!project) {
        throw new NotFoundError('Project', data.projectId);
      }
    }

    return await this.issueService.create(data);
  }

  async get(id: string): Promise<LinearIssue | null> {
    return await this.issueService.get(id);
  }

  async getByIdentifier(identifier: string): Promise<LinearIssue | null> {
    return await this.issueService.getByIdentifier(identifier);
  }

  async getWithRelations(id: string): Promise<IssueWithRelations | null> {
    const issue = await this.issueService.get(id);
    if (!issue) {
      return null;
    }

    const [team, assignee, comments, attachments, labels] = await Promise.all([
      issue.team,
      issue.assignee,
      issue.comments(),
      issue.attachments(),
      issue.labels(),
    ]);

    let project = null;
    if (issue.project) {
      project = await issue.project;
    }

    return {
      issue,
      team,
      project,
      assignee,
      comments: comments.nodes,
      attachments: attachments.nodes,
      labels: labels.nodes,
    };
  }

  async update(id: string, data: IssueUpdate): Promise<LinearIssue> {
    logger.info(`Updating issue: ${id}`);

    if (data.projectId) {
      const project = await this.projectService.get(data.projectId);
      if (!project) {
        throw new NotFoundError('Project', data.projectId);
      }
    }

    return await this.issueService.update(id, data);
  }

  async delete(id: string): Promise<boolean> {
    logger.info(`Deleting issue: ${id}`);
    return await this.issueService.delete(id);
  }

  async archive(id: string): Promise<boolean> {
    logger.info(`Archiving issue: ${id}`);
    return await this.issueService.archive(id);
  }

  async list(filter?: IssueFilter, pagination?: Pagination) {
    const connection = await this.issueService.list(filter, pagination);
    const nodes = await connection.nodes;
    const pageInfo = await connection.pageInfo;

    return {
      issues: nodes,
      pageInfo,
      totalCount: nodes.length,
    };
  }

  async bulkUpdate(data: IssueBulkUpdate) {
    logger.info(`Bulk updating ${data.issueIds.length} issues`);
    return await this.issueService.bulkUpdate(data);
  }

  async moveToProject(issueId: string, projectId: string): Promise<LinearIssue> {
    const [issue, project] = await Promise.all([
      this.issueService.get(issueId),
      this.projectService.get(projectId),
    ]);

    if (!issue) {
      throw new NotFoundError('Issue', issueId);
    }
    if (!project) {
      throw new NotFoundError('Project', projectId);
    }

    return await this.issueService.update(issueId, { projectId });
  }

  async assignToUser(issueId: string, userId: string): Promise<LinearIssue> {
    const issue = await this.issueService.get(issueId);
    if (!issue) {
      throw new NotFoundError('Issue', issueId);
    }

    return await this.issueService.update(issueId, { assigneeId: userId });
  }

  async unassign(issueId: string): Promise<LinearIssue> {
    const issue = await this.issueService.get(issueId);
    if (!issue) {
      throw new NotFoundError('Issue', issueId);
    }

    return await this.issueService.update(issueId, { assigneeId: null });
  }

  async changePriority(issueId: string, priority: number): Promise<LinearIssue> {
    if (priority < 0 || priority > 4) {
      throw new Error('Priority must be between 0 and 4');
    }

    const issue = await this.issueService.get(issueId);
    if (!issue) {
      throw new NotFoundError('Issue', issueId);
    }

    return await this.issueService.update(issueId, { priority });
  }

  async addComment(issueId: string, body: string): Promise<boolean> {
    const issue = await this.issueService.get(issueId);
    if (!issue) {
      throw new NotFoundError('Issue', issueId);
    }

    return await this.issueService.addComment(issueId, body);
  }

  async addLabels(issueId: string, labelIds: string[]): Promise<LinearIssue> {
    return await this.issueService.addLabels(issueId, labelIds);
  }

  async removeLabels(issueId: string, labelIds: string[]): Promise<LinearIssue> {
    return await this.issueService.removeLabels(issueId, labelIds);
  }

  async getSubIssues(issueId: string) {
    const issue = await this.issueService.get(issueId);
    if (!issue) {
      throw new NotFoundError('Issue', issueId);
    }

    const children = await issue.children();
    return children.nodes;
  }

  async createSubIssue(parentId: string, data: IssueCreate): Promise<LinearIssue> {
    const parent = await this.issueService.get(parentId);
    if (!parent) {
      throw new NotFoundError('Parent issue', parentId);
    }

    let teamId = data.teamId;
    if (!teamId && parent.team) {
      const parentTeam = await parent.team;
      teamId = parentTeam.id;
    }

    const subIssueData: IssueCreate = {
      ...data,
      parentId,
      teamId: teamId,
    };

    return await this.issueService.create(subIssueData);
  }
}

import { IssueEntity } from '../entities/issue.entity';
import { TeamService } from '@features/team/service';
import { ProjectService } from '@features/project/service';
import { logger } from '@atoms/shared/logger';
import { NotFoundError } from '@atoms/types/common';

export interface SprintPlanningOptions {
  teamId: string;
  cycleId: string;
  issueIds: string[];
  projectId?: string;
}

export interface SprintPlanningResult {
  success: boolean;
  movedIssues: string[];
  failedIssues: Array<{ issueId: string; error: string }>;
  summary: {
    totalIssues: number;
    successCount: number;
    failureCount: number;
    totalEstimate?: number;
  };
}

export class SprintPlanningWorkflow {
  private issueEntity: IssueEntity;
  private teamService: TeamService;
  private projectService: ProjectService;

  constructor() {
    this.issueEntity = new IssueEntity();
    this.teamService = new TeamService();
    this.projectService = new ProjectService();
  }

  async planSprint(options: SprintPlanningOptions): Promise<SprintPlanningResult> {
    logger.info('Starting sprint planning workflow', options);

    const team = await this.teamService.get(options.teamId);
    if (!team) {
      throw new NotFoundError('Team', options.teamId);
    }

    const cycles = await this.teamService.getCycles(options.teamId);
    const cycle = cycles.nodes.find((c) => c.id === options.cycleId);
    if (!cycle) {
      throw new NotFoundError('Cycle', options.cycleId);
    }

    if (options.projectId) {
      const project = await this.projectService.get(options.projectId);
      if (!project) {
        throw new NotFoundError('Project', options.projectId);
      }
    }

    const result: SprintPlanningResult = {
      success: false,
      movedIssues: [],
      failedIssues: [],
      summary: {
        totalIssues: options.issueIds.length,
        successCount: 0,
        failureCount: 0,
        totalEstimate: 0,
      },
    };

    for (const issueId of options.issueIds) {
      try {
        const issue = await this.issueEntity.get(issueId);
        if (!issue) {
          result.failedIssues.push({
            issueId,
            error: 'Issue not found',
          });
          result.summary.failureCount++;
          continue;
        }

        const updateData: any = { cycleId: options.cycleId };
        if (options.projectId) {
          updateData.projectId = options.projectId;
        }

        await this.issueEntity.update(issueId, updateData);

        result.movedIssues.push(issueId);
        result.summary.successCount++;

        if (issue.estimate) {
          result.summary.totalEstimate! += issue.estimate;
        }

        logger.success(`Issue ${issue.identifier} added to sprint`);
      } catch (error: any) {
        result.failedIssues.push({
          issueId,
          error: error.message || 'Unknown error',
        });
        result.summary.failureCount++;
        logger.error(`Failed to add issue ${issueId} to sprint`, error);
      }
    }

    result.success = result.summary.failureCount === 0;

    logger.info('Sprint planning completed', result.summary);

    return result;
  }

  async calculateSprintCapacity(teamId: string, cycleId: string) {
    const team = await this.teamService.get(teamId);
    if (!team) {
      throw new NotFoundError('Team', teamId);
    }

    const issues = await this.issueEntity.list({
      teamId,
      cycleId,
      state: 'unstarted',
      includeArchived: false,
    });

    const capacity = {
      totalIssues: issues.issues.length,
      totalEstimate: 0,
      byPriority: {
        urgent: 0,
        high: 0,
        medium: 0,
        low: 0,
        none: 0,
      },
      byAssignee: new Map<string, number>(),
    };

    for (const issue of issues.issues) {
      if (issue.estimate) {
        capacity.totalEstimate += issue.estimate;
      }

      const priority = issue.priority || 0;
      if (priority === 4) {
        capacity.byPriority.urgent++;
      } else if (priority === 3) {
        capacity.byPriority.high++;
      } else if (priority === 2) {
        capacity.byPriority.medium++;
      } else if (priority === 1) {
        capacity.byPriority.low++;
      } else {
        capacity.byPriority.none++;
      }

      if (issue.assignee) {
        const assignee = await issue.assignee;
        if (assignee) {
          const assigneeId = assignee.id;
          const current = capacity.byAssignee.get(assigneeId) || 0;
          capacity.byAssignee.set(assigneeId, current + (issue.estimate || 0));
        }
      }
    }

    return capacity;
  }

  async autoAssignIssues(teamId: string, issueIds: string[]) {
    const team = await this.teamService.get(teamId);
    if (!team) {
      throw new NotFoundError('Team', teamId);
    }

    const members = await this.teamService.getMembers(teamId);
    const memberNodes = await members.nodes;

    if (memberNodes.length === 0) {
      throw new Error('Team has no members');
    }

    const workload = new Map<string, number>();
    memberNodes.forEach((member) => workload.set(member.id, 0));

    const existingIssues = await this.issueEntity.list({
      teamId,
      state: 'unstarted',
      includeArchived: false,
    });

    for (const issue of existingIssues.issues) {
      if (issue.assignee) {
        const assignee = await issue.assignee;
        if (assignee && workload.has(assignee.id)) {
          const current = workload.get(assignee.id) || 0;
          workload.set(assignee.id, current + (issue.estimate || 1));
        }
      }
    }

    const results = [];

    for (const issueId of issueIds) {
      try {
        const issue = await this.issueEntity.get(issueId);
        if (!issue) {
          results.push({ issueId, success: false, error: 'Issue not found' });
          continue;
        }

        const [assigneeId] = [...workload.entries()].sort((a, b) => a[1] - b[1])[0];

        await this.issueEntity.assignToUser(issueId, assigneeId);

        const current = workload.get(assigneeId) || 0;
        workload.set(assigneeId, current + (issue.estimate || 1));

        results.push({ issueId, success: true, assigneeId });
        logger.success(`Issue ${issue.identifier} assigned`);
      } catch (error: any) {
        results.push({ issueId, success: false, error: error.message });
      }
    }

    return results;
  }
}

import { Command } from 'commander';
import chalk from 'chalk';
import ora from 'ora';
import { IssueEntity } from '@molecules/entities/issue.entity';
import { IssueCreate, IssueUpdate } from '@features/issue/schemas';
import { logger } from '@atoms/shared/logger';

export function issueCommands(program: Command) {
  const issue = program.command('issue').description('Manage Linear issues');

  issue
    .command('create')
    .description('Create a new issue')
    .requiredOption('-t, --title <title>', 'Issue title')
    .requiredOption('--team <teamId>', 'Team ID')
    .option('-d, --description <description>', 'Issue description')
    .option('-a, --assignee <assigneeId>', 'Assignee ID')
    .option('-p, --priority <priority>', 'Priority (0-4)', (value) => parseInt(value))
    .option('--project <projectId>', 'Project ID')
    .option('--cycle <cycleId>', 'Cycle ID')
    .option('--estimate <estimate>', 'Estimate', (value) => parseInt(value))
    .option('--labels <labelIds>', 'Comma-separated label IDs')
    .action(async (options) => {
      const spinner = ora('Creating issue...').start();
      try {
        const issueEntity = new IssueEntity();

        const data: IssueCreate = {
          title: options.title,
          teamId: options.team,
          description: options.description,
          assigneeId: options.assignee,
          priority: options.priority,
          projectId: options.project,
          cycleId: options.cycle,
          estimate: options.estimate,
          labelIds: options.labels?.split(','),
        };

        const issue = await issueEntity.create(data);
        spinner.succeed(`Issue created: ${chalk.green(issue.identifier)} - ${issue.title}`);
        console.log(chalk.gray(`URL: ${issue.url}`));
      } catch (error: any) {
        spinner.fail('Failed to create issue');
        logger.error('Error', error);
      }
    });

  issue
    .command('get <identifier>')
    .description('Get an issue by ID or identifier')
    .option('--with-relations', 'Include related data')
    .action(async (identifier, options) => {
      const spinner = ora('Fetching issue...').start();
      try {
        const issueEntity = new IssueEntity();

        let issue;
        if (identifier.includes('-')) {
          issue = await issueEntity.getByIdentifier(identifier);
        } else {
          if (options.withRelations) {
            const result = await issueEntity.getWithRelations(identifier);
            if (result) {
              spinner.succeed(`Found issue: ${chalk.green(result.issue.identifier)}`);
              const state = result.issue.state ? await result.issue.state : null;
              console.log('\nIssue Details:');
              console.log(`  Title: ${result.issue.title}`);
              console.log(`  State: ${state?.name || 'Unknown'}`);
              console.log(`  Priority: ${result.issue.priority || 'None'}`);
              console.log(`  Assignee: ${result.assignee?.name || 'Unassigned'}`);
              console.log(`  Team: ${result.team?.name || 'Unknown'}`);
              console.log(`  Project: ${result.project?.name || 'None'}`);
              console.log(`  Comments: ${result.comments?.length || 0}`);
              console.log(`  Labels: ${result.labels?.map((l) => l.name).join(', ') || 'None'}`);
              console.log(`  URL: ${result.issue.url}`);
              return;
            }
          } else {
            issue = await issueEntity.get(identifier);
          }
        }

        if (issue) {
          spinner.succeed(`Found issue: ${chalk.green(issue.identifier)}`);
          console.log('\nIssue Details:');
          console.log(`  Title: ${issue.title}`);
          console.log(`  Description: ${issue.description || 'No description'}`);
          console.log(`  Priority: ${issue.priority || 'None'}`);
          console.log(`  Estimate: ${issue.estimate || 'None'}`);
          console.log(`  URL: ${issue.url}`);
        } else {
          spinner.fail('Issue not found');
        }
      } catch (error: any) {
        spinner.fail('Failed to fetch issue');
        logger.error('Error', error);
      }
    });

  issue
    .command('update <id>')
    .description('Update an issue')
    .option('-t, --title <title>', 'Issue title')
    .option('-d, --description <description>', 'Issue description')
    .option('-a, --assignee <assigneeId>', 'Assignee ID')
    .option('-p, --priority <priority>', 'Priority (0-4)', (value) => parseInt(value))
    .option('--project <projectId>', 'Project ID')
    .option('--cycle <cycleId>', 'Cycle ID')
    .option('--estimate <estimate>', 'Estimate', (value) => parseInt(value))
    .option('--state <stateId>', 'State ID')
    .action(async (id, options) => {
      const spinner = ora('Updating issue...').start();
      try {
        const issueEntity = new IssueEntity();

        const data: IssueUpdate = {};
        if (options.title) {
          data.title = options.title;
        }
        if (options.description) {
          data.description = options.description;
        }
        if (options.assignee) {
          data.assigneeId = options.assignee;
        }
        if (options.priority !== undefined) {
          data.priority = options.priority;
        }
        if (options.project) {
          data.projectId = options.project;
        }
        if (options.cycle) {
          data.cycleId = options.cycle;
        }
        if (options.estimate !== undefined) {
          data.estimate = options.estimate;
        }
        if (options.state) {
          data.stateId = options.state;
        }

        const issue = await issueEntity.update(id, data);
        spinner.succeed(`Issue updated: ${chalk.green(issue.identifier)}`);
      } catch (error: any) {
        spinner.fail('Failed to update issue');
        logger.error('Error', error);
      }
    });

  issue
    .command('list')
    .description('List issues')
    .option('--team <teamId>', 'Filter by team ID')
    .option('--assignee <assigneeId>', 'Filter by assignee ID')
    .option('--project <projectId>', 'Filter by project ID')
    .option('--cycle <cycleId>', 'Filter by cycle ID')
    .option('--state <state>', 'Filter by state')
    .option('--priority <priority>', 'Filter by priority', (value) => parseInt(value))
    .option('--search <query>', 'Search query')
    .option('--limit <limit>', 'Number of issues to fetch', (value) => parseInt(value), 20)
    .action(async (options) => {
      const spinner = ora('Fetching issues...').start();
      try {
        const issueEntity = new IssueEntity();

        const filter: any = {};
        if (options.team) {
          filter.teamId = options.team;
        }
        if (options.assignee) {
          filter.assigneeId = options.assignee;
        }
        if (options.project) {
          filter.projectId = options.project;
        }
        if (options.cycle) {
          filter.cycleId = options.cycle;
        }
        if (options.state) {
          filter.state = options.state;
        }
        if (options.priority !== undefined) {
          filter.priority = options.priority;
        }
        if (options.search) {
          filter.searchQuery = options.search;
        }

        const result = await issueEntity.list(filter, { first: options.limit });

        spinner.succeed(`Found ${result.issues.length} issues`);

        if (result.issues.length > 0) {
          console.log('\nIssues:');
          for (const issue of result.issues) {
            const priority = issue.priority ? `P${issue.priority}` : 'None';
            const assigneeObj = issue.assignee ? await issue.assignee : null;
            const assignee = assigneeObj?.name || 'Unassigned';
            const stateObj = issue.state ? await issue.state : null;
            console.log(`  ${chalk.green(issue.identifier)} - ${issue.title}`);
            console.log(
              `    Priority: ${priority} | Assignee: ${assignee} | State: ${stateObj?.name || 'Unknown'}`,
            );
          }
        }
      } catch (error: any) {
        spinner.fail('Failed to fetch issues');
        logger.error('Error', error);
      }
    });

  issue
    .command('delete <id>')
    .description('Delete an issue')
    .option('--confirm', 'Skip confirmation')
    .action(async (id, options) => {
      if (!options.confirm) {
        console.log(chalk.yellow('⚠️  This will permanently delete the issue.'));
        console.log('Use --confirm flag to skip this warning.');
        return;
      }

      const spinner = ora('Deleting issue...').start();
      try {
        const issueEntity = new IssueEntity();
        await issueEntity.delete(id);
        spinner.succeed('Issue deleted successfully');
      } catch (error: any) {
        spinner.fail('Failed to delete issue');
        logger.error('Error', error);
      }
    });

  issue
    .command('comment <id> <message>')
    .description('Add a comment to an issue')
    .action(async (id, message) => {
      const spinner = ora('Adding comment...').start();
      try {
        const issueEntity = new IssueEntity();
        await issueEntity.addComment(id, message);
        spinner.succeed('Comment added successfully');
      } catch (error: any) {
        spinner.fail('Failed to add comment');
        logger.error('Error', error);
      }
    });

  issue
    .command('assign <id> <userId>')
    .description('Assign an issue to a user')
    .action(async (id, userId) => {
